from collections import defaultdict
import re

def detecter_brute_force(lignes, seuil=5, fenetre_minutes=10):
    """
    Détecte les attaques brute force SSH.
    Alerte si une IP dépasse le seuil dans la fenêtre de temps.
    """
    echecs_par_ip = defaultdict(list)  # ip → [timestamps]
    pattern = re.compile(
        r"(\w{3}  ?\d+ \d{2}:\d{2}:\d{2}).*Failed password.*from (\d+\.\d+\.\d+\.\d+)"
    )

    for ligne in lignes:
        m = pattern.search(ligne)
        if m:
            echecs_par_ip[m.group(2)].append(m.group(1))

    alertes = []
    for ip, timestamps in echecs_par_ip.items():
        if len(timestamps) >= seuil:
            alertes.append({
                "ip": ip,
                "tentatives": len(timestamps),
                "niveau": "CRITIQUE" if len(timestamps) >= 10 else "HAUTE"
            })

    return alertes

logs = [
    f"Jan 15 10:00:0{i} srv sshd: Failed password for root from 185.220.101.3 port 4510{i}"
    for i in range(8)
]
alertes = detecter_brute_force(logs, seuil=5)
for a in alertes:
    print(f"[{a['niveau']}] Brute force depuis {a['ip']}: {a['tentatives']} tentatives")
