import re

# Patterns d'activité suspecte dans syslog
PATTERNS_SUSPECTS = {
    "sudo_echec":      re.compile(r"sudo.*authentication failure.*user=(\S+)"),
    "crontab_modif":   re.compile(r"crontab.*EDIT.*for (\S+)"),
    "user_ajoute":     re.compile(r"useradd.*new user.*name=(\S+)"),
    "nouveau_service": re.compile(r"systemd.*Started (\S+)"),
    "connexion_root":  re.compile(r"session opened for user root"),
}

def scanner_syslog(lignes):
    alertes = []
    for i, ligne in enumerate(lignes):
        for nom, pattern in PATTERNS_SUSPECTS.items():
            m = pattern.search(ligne)
            if m:
                alertes.append({
                    "ligne": i+1,
                    "type": nom,
                    "detail": m.group(1) if m.lastindex else "",
                    "raw": ligne.strip()
                })
    return alertes

# Test
logs_test = [
    "Jan 15 10:05:00 srv sudo: authentication failure; user=apache",
    "Jan 15 10:06:00 srv useradd[1234]: new user name=backdoor, uid=0",
    "Jan 15 10:07:00 srv systemd: Started sshd.service",
]
for a in scanner_syslog(logs_test):
    print(f"[{a['type']}] Ligne {a['ligne']}: {a['detail']}")
